import java.util.HashSet;
import java.util.TreeSet;
import java.util.LinkedHashSet;
import java.util.Set;

public class SetDemo {
    public static void main(String[] args) {
        // HashSet - unordered, no duplicates
        Set<String> hashSet = new HashSet<>();
        hashSet.add("Apple");
        hashSet.add("Banana");
        hashSet.add("Cherry");
        hashSet.add("Apple"); // Duplicate, won't be added
        hashSet.add("Date");

        System.out.println("HashSet (unordered): " + hashSet);

        // TreeSet - sorted order
        Set<String> treeSet = new TreeSet<>();
        treeSet.add("Zebra");
        treeSet.add("Apple");
        treeSet.add("Monkey");
        treeSet.add("Banana");

        System.out.println("TreeSet (sorted): " + treeSet);

        // LinkedHashSet - insertion order preserved
        Set<String> linkedHashSet = new LinkedHashSet<>();
        linkedHashSet.add("First");
        linkedHashSet.add("Second");
        linkedHashSet.add("Third");
        linkedHashSet.add("First"); // Duplicate

        System.out.println("LinkedHashSet (insertion order): " + linkedHashSet);

        // Set operations
        Set<Integer> set1 = new HashSet<>();
        set1.add(1);
        set1.add(2);
        set1.add(3);
        set1.add(4);

        Set<Integer> set2 = new HashSet<>();
        set2.add(3);
        set2.add(4);
        set2.add(5);
        set2.add(6);

        // Union
        Set<Integer> union = new HashSet<>(set1);
        union.addAll(set2);
        System.out.println("\nSet1: " + set1);
        System.out.println("Set2: " + set2);
        System.out.println("Union: " + union);

        // Intersection
        Set<Integer> intersection = new HashSet<>(set1);
        intersection.retainAll(set2);
        System.out.println("Intersection: " + intersection);

        // Difference
        Set<Integer> difference = new HashSet<>(set1);
        difference.removeAll(set2);
        System.out.println("Difference (set1 - set2): " + difference);

        // Subset check
        System.out.println("Is set1 subset of union? " + union.containsAll(set1));
    }
}

import java.util.HashMap;
import java.util.TreeMap;
import java.util.LinkedHashMap;
import java.util.Map;

public class MapDemo {
    public static void main(String[] args) {
        // HashMap - unordered
        Map<String, Integer> hashMap = new HashMap<>();
        hashMap.put("Alice", 85);
        hashMap.put("Bob", 92);
        hashMap.put("Charlie", 78);
        hashMap.put("Alice", 90); // Updates existing key

        System.out.println("HashMap: " + hashMap);
        System.out.println("Bob's score: " + hashMap.get("Bob"));

        // TreeMap - sorted by keys
        Map<String, Integer> treeMap = new TreeMap<>();
        treeMap.put("Zebra", 100);
        treeMap.put("Apple", 95);
        treeMap.put("Monkey", 85);

        System.out.println("\nTreeMap (sorted by keys): " + treeMap);

        // LinkedHashMap - insertion order
        Map<String, Integer> linkedHashMap = new LinkedHashMap<>();
        linkedHashMap.put("First", 1);
        linkedHashMap.put("Second", 2);
        linkedHashMap.put("Third", 3);

        System.out.println("\nLinkedHashMap (insertion order): " + linkedHashMap);

        // Map operations
        System.out.println("\nMap Operations:");
        System.out.println("Contains key 'Alice': " + hashMap.containsKey("Alice"));
        System.out.println("Contains value 92: " + hashMap.containsValue(92));
        System.out.println("Map size: " + hashMap.size());

        // Iterating through Map
        System.out.println("\nIterating through HashMap:");
        System.out.println("Using keySet():");
        for (String key : hashMap.keySet()) {
            System.out.println(key + " -> " + hashMap.get(key));
        }

        System.out.println("\nUsing entrySet():");
        for (Map.Entry<String, Integer> entry : hashMap.entrySet()) {
            System.out.println(entry.getKey() + " -> " + entry.getValue());
        }

        System.out.println("\nUsing forEach():");
        hashMap.forEach((key, value) -> 
            System.out.println(key + " -> " + value)
        );

        // Remove entry
        hashMap.remove("Charlie");
        System.out.println("\nAfter removing Charlie: " + hashMap);

        // Clear map
        hashMap.clear();
        System.out.println("After clear, isEmpty: " + hashMap.isEmpty());
    }
}

