import java.io.*;
import java.util.Scanner;

public class IODemo {

    // Write to file using FileWriter
    public static void writeToFile(String filename, String content) {
        try (BufferedWriter writer = new BufferedWriter(new FileWriter(filename))) {
            writer.write(content);
            System.out.println("Successfully wrote to file: " + filename);
        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }

    // Read from file using BufferedReader
    public static void readFromFile(String filename) {
        try (BufferedReader reader = new BufferedReader(new FileReader(filename))) {
            String line;
            System.out.println("\nReading file: " + filename);
            System.out.println("===================");
            while ((line = reader.readLine()) != null) {
                System.out.println(line);
            }
        } catch (IOException e) {
            System.out.println("Error reading file: " + e.getMessage());
        }
    }

    // Copy file using byte streams
    public static void copyFile(String source, String destination) {
        try (FileInputStream fis = new FileInputStream(source);
             FileOutputStream fos = new FileOutputStream(destination)) {

            byte[] buffer = new byte[1024];
            int bytesRead;

            while ((bytesRead = fis.read(buffer)) != -1) {
                fos.write(buffer, 0, bytesRead);
            }
            System.out.println("File copied successfully from " + source + " to " + destination);
        } catch (IOException e) {
            System.out.println("Error copying file: " + e.getMessage());
        }
    }

    // Serialization example
    static class Student implements Serializable {
        private static final long serialVersionUID = 1L;
        private String name;
        private int age;
        private transient String password; // transient field won't be serialized

        public Student(String name, int age, String password) {
            this.name = name;
            this.age = age;
            this.password = password;
        }

        @Override
        public String toString() {
            return "Student{name='" + name + "', age=" + age + ", password='" + password + "'}";
        }
    }

    // Serialize object to file
    public static void serializeObject(String filename, Object obj) {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(obj);
            System.out.println("Object serialized successfully to " + filename);
        } catch (IOException e) {
            System.out.println("Error serializing object: " + e.getMessage());
        }
    }

    // Deserialize object from file
    public static Object deserializeObject(String filename) {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            return ois.readObject();
        } catch (IOException | ClassNotFoundException e) {
            System.out.println("Error deserializing object: " + e.getMessage());
            return null;
        }
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        // File writing and reading
        System.out.print("Enter text to write to file: ");
        String text = scanner.nextLine();
        writeToFile("example.txt", text);
        readFromFile("example.txt");

        // File copying
        copyFile("example.txt", "example_copy.txt");

        // Serialization
        Student student = new Student("Alice", 20, "secret123");
        System.out.println("\nOriginal Student: " + student);

        serializeObject("student.ser", student);

        Student deserializedStudent = (Student) deserializeObject("student.ser");
        System.out.println("Deserialized Student: " + deserializedStudent);

        // Console input/output
        System.out.print("\nEnter your name: ");
        String name = scanner.nextLine();
        System.out.println("Hello, " + name + "!");

        // Using System.out for formatted output
        System.out.printf("\nFormatted output: Name: %s, Age: %d%n", name, 25);

        scanner.close();

        // Clean up created files
        new File("example.txt").delete();
        new File("example_copy.txt").delete();
        new File("student.ser").delete();
    }
}

// Extending Thread class
class MyThread extends Thread {
    private String threadName;

    public MyThread(String name) {
        this.threadName = name;
    }

    @Override
    public void run() {
        try {
            for (int i = 1; i <= 5; i++) {
                System.out.println(threadName + " - Count: " + i);
                Thread.sleep(500); // Pause for 500ms
            }
        } catch (InterruptedException e) {
            System.out.println(threadName + " interrupted.");
        }
        System.out.println(threadName + " exiting.");
    }
}

