public class OptionalDemo {

    // Traditional null-checking approach (prone to NullPointerException)
    public static String getCityTraditional(User user) {
        if (user != null) {
            Address address = user.getAddress();
            if (address != null) {
                return address.getCity();
            }
        }
        return "Unknown";
    }

    // Optional-based approach
    public static Optional<String> getCityOptional(User user) {
        return Optional.ofNullable(user)
                       .map(User::getAddress)
                       .map(Address::getCity);
    }

    // Repository simulation
    static class UserRepository {
        private Map<String, User> users = new HashMap<>();

        public UserRepository() {
            // Sample data
            users.put("1", new User("1", "Alice", "alice@example.com", 
                new Address("123 Main St", "New York", "USA")));
            users.put("2", new User("2", "Bob", null, 
                new Address("456 Oak Ave", "London", "UK")));
            users.put("3", new User("3", "Charlie", "charlie@example.com", null));
        }

        public Optional<User> findById(String id) {
            return Optional.ofNullable(users.get(id));
        }
    }

    public static void main(String[] args) {
        UserRepository repository = new UserRepository();

        System.out.println("=== Creating Optional Objects ===");

        // Different ways to create Optional
        Optional<String> emptyOptional = Optional.empty();
        Optional<String> nonNullOptional = Optional.of("Hello");
        Optional<String> nullableOptional = Optional.ofNullable(null);
        Optional<String> nullableWithValue = Optional.ofNullable("World");

        System.out.println("Empty optional: " + emptyOptional);
        System.out.println("Non-null optional: " + nonNullOptional);
        System.out.println("Nullable (null) optional: " + nullableOptional);
        System.out.println("Nullable (with value) optional: " + nullableWithValue);

        System.out.println("\n=== Basic Optional Operations ===");

        // isPresent() and get()
        Optional<String> nameOptional = Optional.of("Alice");
        if (nameOptional.isPresent()) {
            System.out.println("Name is present: " + nameOptional.get());
        }

        // ifPresent()
        nameOptional.ifPresent(name -> 
            System.out.println("Name (using ifPresent): " + name)
        );

        // orElse()
        Optional<String> emptyName = Optional.empty();
        String result = emptyName.orElse("Default Name");
        System.out.println("Result with orElse: " + result);

        // orElseGet() - lazy evaluation
        String lazyResult = emptyName.orElseGet(() -> {
            System.out.println("Computing default value...");
            return "Computed Default";
        });
        System.out.println("Result with orElseGet: " + lazyResult);

        // orElseThrow()
        try {
            String value = emptyName.orElseThrow(() -> 
                new IllegalArgumentException("Value not present")
            );
        } catch (IllegalArgumentException e) {
            System.out.println("Caught exception: " + e.getMessage());
        }

        System.out.println("\n=== Optional with Map and FlatMap ===");

        // Map - transforms value if present
        Optional<User> userOptional = repository.findById("1");
        Optional<String> emailOptional = userOptional.map(User::getEmail);
        emailOptional.ifPresent(email -> 
            System.out.println("User 1 email: " + email)
        );

        // FlatMap - for nested Optionals
        Optional<String> cityOptional = userOptional
            .flatMap(user -> Optional.ofNullable(user.getAddress()))
            .map(Address::getCity);
        cityOptional.ifPresent(city -> 
            System.out.println("User 1 city: " + city)
        );

        System.out.println("\n=== Filtering with Optional ===");

        // filter()
        userOptional.filter(user -> user.getEmail() != null)
                    .ifPresent(user -> 
                        System.out.println("User with email: " + user.getName())
                    );

        Optional<User> userWithoutAddress = repository.findById("3");
        userWithoutAddress.filter(user -> user.getAddress() != null)
                          .ifPresentOrElse(
                              user -> System.out.println("User has address: " + user.getName()),
                              () -> System.out.println("User 3 has no address")
                          );

        System.out.println("\n=== Chaining Optional Operations ===");

        // Complex chaining example
        String finalResult = repository.findById("2")
            .map(User::getEmail)
            .filter(email -> email.contains("@"))
            .map(String::toUpperCase)
            .orElse("NO_VALID_EMAIL");

        System.out.println("User 2 email result: " + finalResult);

        System.out.println("\n=== Practical Examples ===");

        // Example 1: Safe string processing
        String input = "  Hello World  ";
        String processed = Optional.ofNullable(input)
            .map(String::trim)
            .filter(s -> !s.isEmpty())
            .map(String::toUpperCase)
            .orElse("DEFAULT");
        System.out.println("Processed input: " + processed);

        // Example 2: Configuration with defaults
        Map<String, String> config = new HashMap<>();
        config.put("timeout", "5000");
        // config.put("retries", "3"); // This key is missing

        int timeout = Optional.ofNullable(config.get("timeout"))
            .map(Integer::parseInt)
            .filter(t -> t > 0)
            .orElse(1000);

        int retries = Optional.ofNullable(config.get("retries"))
            .map(Integer::parseInt)
            .filter(r -> r > 0)
            .orElse(5);

        System.out.println("Timeout: " + timeout + "ms");
        System.out.println("Retries: " + retries);

        // Example 3: Method returning Optional
        System.out.println("\nGetting cities using Optional:");
        for (String userId : Arrays.asList("1", "2", "3", "4")) {
            String city = getCityOptional(repository.findById(userId).orElse(null))
                .orElse("City not available");
            System.out.println("User " + userId + " city: " + city);
        }

        System.out.println("\n=== Optional with Streams ===");

        // Stream of Optionals
        List<Optional<String>> optionalList = Arrays.asList(
            Optional.of("A"),
            Optional.empty(),
            Optional.of("B"),
            Optional.of("C"),
            Optional.empty()
        );

        // Filter out empty Optionals and get values
        List<String> values = optionalList.stream()
            .filter(Optional::isPresent)
            .map(Optional::get)
            .collect(Collectors.toList());

        System.out.println("Values from optional list: " + values);

        // Using flatMap with Stream
        List<String> flatValues = optionalList.stream()
            .flatMap(opt -> opt.map(Stream::of).orElseGet(Stream::empty))
            .collect(Collectors.toList());

        System.out.println("Values using flatMap: " + flatValues);

        // Java 9+ features (if using Java 9+)
        System.out.println("\n=== Java 9+ Optional Features ===");

        // or() - alternative Optional if empty
        Optional<String> primary = Optional.empty();
        Optional<String> secondary = Optional.of("Secondary");
        Optional<String> resultOr = primary.or(() -> secondary);
        resultOr.ifPresent(v -> System.out.println("or() result: " + v));

        // ifPresentOrElse()
        Optional<String> maybeValue = Optional.of("Present Value");
        maybeValue.ifPresentOrElse(
            value -> System.out.println("Value is present: " + value),
            () -> System.out.println("Value is absent")
        );

        // stream() - convert Optional to Stream
        List<String> streamResult = maybeValue.stream()
            .map(String::toUpperCase)
            .collect(Collectors.toList());
        System.out.println("Stream from Optional: " + streamResult);

        System.out.println("\n=== Best Practices ===");
        System.out.println("1. Never call get() without checking isPresent() first");
        System.out.println("2. Use orElse/orElseGet for default values");
        System.out.println("3. Prefer map/flatMap over nested if-checks");
        System.out.println("4. Use Optional as return type, not parameter");
        System.out.println("5. Don't use Optional for collections - use empty collections instead");

        System.out.println("\nOptional class demonstration completed!");
    }
}

import java.time.*;
import java.time.format.*;
