        System.out.println("ISO format: " + today.format(isoFormatter));
        System.out.println("Basic ISO format: " + today.format(basicFormatter));

        // Custom formatters
        DateTimeFormatter customFormatter = DateTimeFormatter.ofPattern("dd/MM/yyyy");
        System.out.println("Custom format (dd/MM/yyyy): " + today.format(customFormatter));

        DateTimeFormatter fullFormatter = DateTimeFormatter.ofPattern("EEEE, MMMM dd, yyyy hh:mm a");
