        // Parsing with custom formatter
        String dateString = "25/12/2024";
        LocalDate christmas = LocalDate.parse(dateString, customFormatter);
        System.out.println("Parsed Christmas date: " + christmas);

        // Localized formatters
        DateTimeFormatter germanFormatter = DateTimeFormatter
            .ofLocalizedDate(FormatStyle.FULL)
            .withLocale(Locale.GERMAN);
        System.out.println("German format: " + today.format(germanFormatter));

        System.out.println("\n=== Time Zones ===");

        // Working with time zones
        ZoneId londonZone = ZoneId.of("Europe/London");
        ZoneId newYorkZone = ZoneId.of("America/New_York");
        ZoneId tokyoZone = ZoneId.of("Asia/Tokyo");

        ZonedDateTime londonTime = ZonedDateTime.now(londonZone);
        ZonedDateTime newYorkTime = ZonedDateTime.now(newYorkZone);
        ZonedDateTime tokyoTime = ZonedDateTime.now(tokyoZone);

        System.out.println("London time: " + londonTime);
        System.out.println("New York time: " + newYorkTime);
        System.out.println("Tokyo time: " + tokyoTime);

        // Convert between time zones
        ZonedDateTime londonToNewYork = londonTime.withZoneSameInstant(newYorkZone);
        System.out.println("London time in New York: " + londonToNewYork);

        // All available zone ids
        System.out.println("\nFirst 5 time zones:");
        ZoneId.getAvailableZoneIds().stream()
              .sorted()
              .limit(5)
              .forEach(System.out::println);

        System.out.println("\n=== Practical Examples ===");

        // Example 1: Calculate days until birthday
        LocalDate nextBirthday = birthDate.withYear(today.getYear());
        if (nextBirthday.isBefore(today) || nextBirthday.isEqual(today)) {
            nextBirthday = nextBirthday.plusYears(1);
        }
        long daysUntilBirthday = ChronoUnit.DAYS.between(today, nextBirthday);
        System.out.println("Days until next birthday: " + daysUntilBirthday);

        // Example 2: Business hours calculation
        LocalDateTime orderTime = LocalDateTime.of(2024, 3, 15, 16, 45); // Friday 4:45 PM
        LocalDateTime deliveryTime = calculateDeliveryTime(orderTime, 48); // 48 business hours
        System.out.println("Order time: " + orderTime.format(fullFormatter));
        System.out.println("Expected delivery: " + deliveryTime.format(fullFormatter));

        // Example 3: Age validation
        LocalDate userBirthDate = LocalDate.of(2008, 1, 1);
        boolean isAdult = Period.between(userBirthDate, today).getYears() >= 18;
        System.out.println("\nUser born on " + userBirthDate + " is adult: " + isAdult);

        // Example 4: Time difference between two instants
        Instant startInstant = Instant.now();
        try {
            Thread.sleep(100); // Simulate some work
        } catch (InterruptedException e) {
            e.printStackTrace();
        }
        Instant endInstant = Instant.now();

        Duration elapsed = Duration.between(startInstant, endInstant);
        System.out.println("\nTask took: " + elapsed.toMillis() + " milliseconds");

        // Example 5: Leap year check
        System.out.println("\nLeap year checks:");
        System.out.println("2024 is leap year: " + Year.of(2024).isLeap());
        System.out.println("2023 is leap year: " + Year.of(2023).isLeap());

        // Example 6: First and last day of month
        YearMonth yearMonth = YearMonth.of(2024, Month.MARCH);
        LocalDate firstDay = yearMonth.atDay(1);
        LocalDate lastDay = yearMonth.atEndOfMonth();
        System.out.println("\nMarch 2024:");
        System.out.println("First day: " + firstDay);
        System.out.println("Last day: " + lastDay);

        System.out.println("\nDate and Time API demonstration completed!");
    }

    // Helper method for business hours calculation
    private static LocalDateTime calculateDeliveryTime(LocalDateTime orderTime, int businessHours) {
        LocalDateTime deliveryTime = orderTime;
        int hoursAdded = 0;

        while (hoursAdded < businessHours) {
            deliveryTime = deliveryTime.plusHours(1);

            // Check if it's business hours (9 AM to 5 PM) and weekday
            if (deliveryTime.getHour() >= 9 && deliveryTime.getHour() < 17 && 
                deliveryTime.getDayOfWeek().getValue() <= 5) {
                hoursAdded++;
            }
        }

        return deliveryTime;
    }
}

import java.nio.*;
import java.nio.channels.*;
import java.nio.file.*;
import java.io.*;
import java.util.*;
import java.util.stream.*;

public class NIODemo {
    public static void main(String[] args) {
        System.out.println("=== Path API ===");

        // Creating Path objects
        Path currentDir = Paths.get(".");
        Path homeDir = Paths.get(System.getProperty("user.home"));
        Path absolutePath = Paths.get("/", "usr", "local", "bin");
        Path relativePath = Paths.get("src", "main", "java");

        System.out.println("Current directory: " + currentDir.toAbsolutePath().normalize());
        System.out.println("Home directory: " + homeDir);
        System.out.println("Absolute path: " + absolutePath);
        System.out.println("Relative path: " + relativePath);

        // Path operations
        Path resolvedPath = homeDir.resolve("Documents");
        Path siblingPath = resolvedPath.resolveSibling("Downloads");
        Path relativized = homeDir.relativize(resolvedPath);

        System.out.println("\nPath operations:");
        System.out.println("Resolved path: " + resolvedPath);
        System.out.println("Sibling path: " + siblingPath);
        System.out.println("Relativized path: " + relativized);

        // Path information
        System.out.println("\nPath information:");
        System.out.println("File name: " + resolvedPath.getFileName());
        System.out.println("Parent: " + resolvedPath.getParent());
        System.out.println("Root: " + resolvedPath.getRoot());
        System.out.println("Name count: " + resolvedPath.getNameCount());
        System.out.println("Is absolute: " + resolvedPath.isAbsolute());

        System.out.println("\n=== Files Class Operations ===");

        try {
            // Create temporary directory and files for demo
            Path tempDir = Files.createTempDirectory("nio_demo");
            System.out.println("Created temp directory: " + tempDir);

            // Create files
            Path file1 = tempDir.resolve("test1.txt");
            Path file2 = tempDir.resolve("test2.txt");
            Path subDir = tempDir.resolve("subdirectory");

            Files.createFile(file1);
            Files.createFile(file2);
            Files.createDirectory(subDir);

            System.out.println("\nCreated files and directories:");
            System.out.println("File1: " + file1);
            System.out.println("File2: " + file2);
            System.out.println("Subdirectory: " + subDir);

            // Write to files
            String content = "Hello NIO!\nThis is a test file.\n";
            Files.write(file1, content.getBytes());
            Files.writeString(file2, "Another test file\nWith multiple lines\n");

            // Read from files
            System.out.println("\nReading file1:");
            List<String> lines = Files.readAllLines(file1);
            lines.forEach(System.out::println);

            // File attributes
            System.out.println("\nFile attributes:");
            System.out.println("File1 exists: " + Files.exists(file1));
            System.out.println("File1 size: " + Files.size(file1) + " bytes");
            System.out.println("File1 is regular file: " + Files.isRegularFile(file1));
            System.out.println("File1 is readable: " + Files.isReadable(file1));
            System.out.println("File1 is writable: " + Files.isWritable(file1));
            System.out.println("File1 is executable: " + Files.isExecutable(file1));

            // Copy file
            Path file1Copy = tempDir.resolve("test1_copy.txt");
            Files.copy(file1, file1Copy, StandardCopyOption.REPLACE_EXISTING);
            System.out.println("\nCopied file1 to: " + file1Copy);

            // Move/rename file
            Path renamedFile = tempDir.resolve("renamed_test2.txt");
            Files.move(file2, renamedFile, StandardCopyOption.REPLACE_EXISTING);
            System.out.println("Renamed file2 to: " + renamedFile);

            // List directory contents
            System.out.println("\nDirectory contents:");
            try (Stream<Path> stream = Files.list(tempDir)) {
                stream.forEach(p -> {
                    try {
                        String type = Files.isDirectory(p) ? "DIR" : "FILE";
                        System.out.println(type + "\t" + p.getFileName());
                    } catch (IOException e) {
                        e.printStackTrace();
                    }
                });
            }

            // Walk directory tree
            System.out.println("\nWalking directory tree:");
            try (Stream<Path> walk = Files.walk(tempDir)) {
                walk.forEach(p -> {
                    try {
                        String indent = "  ".repeat(tempDir.relativize(p).getNameCount());
                        String type = Files.isDirectory(p) ? "[DIR]" : "[FILE]";
                        System.out.println(indent + type + " " + p.getFileName());
                    } catch (IOException e) {
                        e.printStackTrace();
                    }
                });
            }

            // Delete files and directory
            Files.delete(file1);
            Files.delete(file1Copy);
            Files.delete(renamedFile);
            Files.delete(subDir);
            Files.delete(tempDir);
            System.out.println("\nCleaned up temporary files and directory.");

        } catch (IOException e) {
            System.out.println("Error in Files operations: " + e.getMessage());
        }

        System.out.println("\n=== Buffer Operations ===");

        // Create a ByteBuffer
        ByteBuffer buffer = ByteBuffer.allocate(1024); // 1KB buffer
        System.out.println("\nBuffer created:");
        printBufferInfo(buffer);

        // Write to buffer
        String message = "Hello, NIO Buffer!";
        buffer.put(message.getBytes());
        System.out.println("\nAfter writing '" + message + "':");
        printBufferInfo(buffer);

        // Flip buffer for reading
        buffer.flip();
        System.out.println("\nAfter flip():");
        printBufferInfo(buffer);

        // Read from buffer
        byte[] readBytes = new byte[buffer.remaining()];
        buffer.get(readBytes);
        System.out.println("Read from buffer: " + new String(readBytes));
        printBufferInfo(buffer);

        // Clear buffer
        buffer.clear();
        System.out.println("\nAfter clear():");
        printBufferInfo(buffer);

        // Different types of buffers
        System.out.println("\n=== Different Buffer Types ===");

        CharBuffer charBuffer = CharBuffer.allocate(50);
        charBuffer.put("Hello CharBuffer");
        charBuffer.flip();

        IntBuffer intBuffer = IntBuffer.allocate(10);
        for (int i = 0; i < 5; i++) {
            intBuffer.put(i * 10);
        }
        intBuffer.flip();

        System.out.println("CharBuffer content:");
        while (charBuffer.hasRemaining()) {
            System.out.print(charBuffer.get());
        }
        System.out.println();

        System.out.println("\nIntBuffer content:");
        while (intBuffer.hasRemaining()) {
            System.out.print(intBuffer.get() + " ");
        }
        System.out.println();

        System.out.println("\n=== Channel Operations ===");

        try {
            // Create test files for channel demo
            Path sourceFile = Files.createTempFile("source", ".txt");
            Path destFile = Files.createTempFile("destination", ".txt");

            // Write some data to source file
            Files.writeString(sourceFile, "This is a test file for channel operations.\n" +
                                        "NIO channels provide faster I/O operations.\n" +
                                        "Using FileChannel for file operations.\n");

            // FileChannel example - Copy file
            System.out.println("\nCopying file using FileChannel:");
            try (FileChannel sourceChannel = FileChannel.open(sourceFile, StandardOpenOption.READ);
                 FileChannel destChannel = FileChannel.open(destFile, StandardOpenOption.WRITE, StandardOpenOption.CREATE)) {

                long bytesTransferred = sourceChannel.transferTo(0, sourceChannel.size(), destChannel);
                System.out.println("Copied " + bytesTransferred + " bytes from " + 
                                 sourceFile.getFileName() + " to " + destFile.getFileName());

                // Verify copy
                String destContent = Files.readString(destFile);
                System.out.println("\nDestination file content (first 50 chars): " + 
                                 destContent.substring(0, Math.min(50, destContent.length())) + "...");
            }

            // Read file using FileChannel
            System.out.println("\nReading file using FileChannel:");
            try (FileChannel readChannel = FileChannel.open(sourceFile, StandardOpenOption.READ)) {
                ByteBuffer readBuffer = ByteBuffer.allocate(256);

                while (readChannel.read(readBuffer) > 0) {
                    readBuffer.flip();
                    while (readBuffer.hasRemaining()) {
                        System.out.print((char) readBuffer.get());
                    }
                    readBuffer.clear();
                }
            }

            // Clean up
            Files.delete(sourceFile);
            Files.delete(destFile);

        } catch (IOException e) {
            System.out.println("Error in channel operations: " + e.getMessage());
        }

        System.out.println("\n=== Selector (Non-blocking I/O) ===");
        System.out.println("Note: Selector is typically used with SocketChannel for network programming.");
        System.out.println("Here's a simple example structure:");

        String selectorExample = "
        try (Selector selector = Selector.open();
             ServerSocketChannel serverChannel = ServerSocketChannel.open()) {

            // Configure non-blocking mode
            serverChannel.configureBlocking(false);
            serverChannel.bind(new InetSocketAddress(8080));
            serverChannel.register(selector, SelectionKey.OP_ACCEPT);

            while (true) {
                selector.select(); // Blocks until events are available
                Set<SelectionKey> selectedKeys = selector.selectedKeys();

                for (SelectionKey key : selectedKeys) {
                    if (key.isAcceptable()) {
                        // Accept connection
                    } else if (key.isReadable()) {
                        // Read data
                    } else if (key.isWritable()) {
                        // Write data
                    }
                }
                selectedKeys.clear();
            }
        }";

        System.out.println(selectorExample);

        System.out.println("\n=== WatchService - Directory Monitoring ===");

        try {
            // Create a temp directory to watch
            Path watchDir = Files.createTempDirectory("watch_demo");
            System.out.println("\nWatching directory: " + watchDir);

            // Create WatchService
            WatchService watchService = FileSystems.getDefault().newWatchService();
            watchDir.register(watchService, 
                StandardWatchEventKinds.ENTRY_CREATE,
                StandardWatchEventKinds.ENTRY_DELETE,
                StandardWatchEventKinds.ENTRY_MODIFY);

            // Start a thread to monitor events
            Thread watchThread = new Thread(() -> {
                try {
                    for (int i = 0; i < 3; i++) { // Monitor for 3 events
                        WatchKey key = watchService.take();

                        for (WatchEvent<?> event : key.pollEvents()) {
                            WatchEvent.Kind<?> kind = event.kind();
                            Path fileName = (Path) event.context();

                            System.out.println("Event: " + kind + " on file: " + fileName);
                        }

                        boolean valid = key.reset();
                        if (!valid) {
                            break;
                        }
                    }
                } catch (InterruptedException e) {
                    System.out.println("Watch service interrupted.");
                }
            });

            watchThread.start();

            // Create some events
            Thread.sleep(500);
            Files.createFile(watchDir.resolve("test1.txt"));
            Thread.sleep(500);
            Files.writeString(watchDir.resolve("test1.txt"), "Hello");
            Thread.sleep(500);
            Files.delete(watchDir.resolve("test1.txt"));

            // Wait for monitoring thread to finish
            watchThread.join(2000);

            // Cleanup
            watchService.close();
            Files.delete(watchDir);

        } catch (IOException | InterruptedException e) {
            System.out.println("Error in WatchService: " + e.getMessage());
        }

        System.out.println("\n=== NIO vs Traditional I/O ===");
        System.out.println("1. NIO uses buffers and channels");
        System.out.println("2. NIO supports non-blocking I/O");
        System.out.println("3. NIO has better performance for large files");
        System.out.println("4. NIO provides more flexible file operations");

        System.out.println("\nNIO demonstration completed!");
    }

    private static void printBufferInfo(ByteBuffer buffer) {
        System.out.println("Position: " + buffer.position());
        System.out.println("Limit: " + buffer.limit());
        System.out.println("Capacity: " + buffer.capacity());
        System.out.println("Remaining: " + buffer.remaining());
    }
}

