        System.out.println("\nRemaining students:");
        studentDAO.getAllStudents().forEach(System.out::println);

        System.out.println("\n=== Advanced JDBC Features ===");

        // Batch processing
        System.out.println("\n1. Batch Processing:");
        try (Connection conn = DatabaseManager.getConnection();
             PreparedStatement pstmt = conn.prepareStatement(
                 "INSERT INTO students (name, email, age) VALUES (?, ?, ?)")) {

            // Add multiple statements to batch
            pstmt.setString(1, "David Wilson");
            pstmt.setString(2, "david@example.com");
            pstmt.setInt(3, 23);
            pstmt.addBatch();

            pstmt.setString(1, "Eva Davis");
            pstmt.setString(2, "eva@example.com");
            pstmt.setInt(3, 24);
            pstmt.addBatch();

            pstmt.setString(1, "Frank Miller");
            pstmt.setString(2, "frank@example.com");
            pstmt.setInt(3, 25);
            pstmt.addBatch();

            int[] batchResults = pstmt.executeBatch();
            System.out.println("Batch insert completed. Rows affected: " + Arrays.toString(batchResults));

        } catch (SQLException e) {
            System.out.println("Error in batch processing: " + e.getMessage());
        }

        // Transactions
        System.out.println("\n2. Transaction Management:");
        Connection conn = null;
        try {
            conn = DatabaseManager.getConnection();
            conn.setAutoCommit(false); // Start transaction

            // Perform multiple operations
            try (PreparedStatement pstmt1 = conn.prepareStatement(
                     "UPDATE students SET age = age + 1 WHERE id = ?");
                 PreparedStatement pstmt2 = conn.prepareStatement(
                     "INSERT INTO students (name, email, age) VALUES (?, ?, ?)")) {

                // Update first student
                pstmt1.setInt(1, id1);
                pstmt1.executeUpdate();

                // Insert new student
                pstmt2.setString(1, "Grace Lee");
                pstmt2.setString(2, "grace@example.com");
                pstmt2.setInt(3, 26);
                pstmt2.executeUpdate();

                // Simulate an error condition
                boolean simulateError = false;
                if (simulateError) {
                    throw new SQLException("Simulated error for rollback");
                }

                // Commit transaction
                conn.commit();
                System.out.println("Transaction committed successfully.");

            }

        } catch (SQLException e) {
            System.out.println("Transaction failed: " + e.getMessage());
            if (conn != null) {
                try {
                    conn.rollback();
                    System.out.println("Transaction rolled back.");
                } catch (SQLException rollbackEx) {
                    System.out.println("Rollback failed: " + rollbackEx.getMessage());
                }
            }
        } finally {
            if (conn != null) {
                try {
                    conn.setAutoCommit(true); // Reset auto-commit
                    conn.close();
                } catch (SQLException e) {
                    System.out.println("Error closing connection: " + e.getMessage());
                }
            }
        }

        // Display final state
        System.out.println("\nFinal student list:");
        studentDAO.getAllStudents().forEach(System.out::println);

        // ResultSet metadata
        System.out.println("\n3. ResultSet Metadata:");
        try (Connection connMeta = DatabaseManager.getConnection();
             Statement stmt = connMeta.createStatement();
             ResultSet rs = stmt.executeQuery("SELECT * FROM students")) {

            ResultSetMetaData metaData = rs.getMetaData();
            int columnCount = metaData.getColumnCount();

            System.out.println("Table: " + metaData.getTableName(1));
            System.out.println("Number of columns: " + columnCount);
            System.out.println("\nColumn Information:");

            for (int i = 1; i <= columnCount; i++) {
                System.out.printf("Column %d: %s (%s)%n", 
                    i,
                    metaData.getColumnName(i),
                    metaData.getColumnTypeName(i));
            }

        } catch (SQLException e) {
            System.out.println("Error getting metadata: " + e.getMessage());
        }

        // CallableStatement (Stored Procedures)
        System.out.println("\n4. CallableStatement (Stored Procedures):");
        System.out.println("Note: H2 doesn't support stored procedures by default.");
        System.out.println("Here's the general syntax:");

        String callableExample = """
        String sql = "{call get_student_by_id(?, ?)}";
        try (CallableStatement cstmt = conn.prepareCall(sql)) {
            cstmt.setInt(1, studentId); // Input parameter
            cstmt.registerOutParameter(2, Types.VARCHAR); // Output parameter
            cstmt.execute();
            String result = cstmt.getString(2);
        }
        """;

        System.out.println(callableExample);

        // Database metadata
        System.out.println("\n5. Database Metadata:");
        try (Connection connDb = DatabaseManager.getConnection()) {
            DatabaseMetaData dbMetaData = connDb.getMetaData();

            System.out.println("Database Product: " + dbMetaData.getDatabaseProductName());
            System.out.println("Database Version: " + dbMetaData.getDatabaseProductVersion());
            System.out.println("JDBC Driver: " + dbMetaData.getDriverName());
            System.out.println("JDBC Version: " + dbMetaData.getDriverVersion());

            // Get all tables
            System.out.println("\nTables in database:");
            try (ResultSet tables = dbMetaData.getTables(null, null, "%", new String[]{"TABLE"})) {
                while (tables.next()) {
                    System.out.println("Table: " + tables.getString("TABLE_NAME"));
                }
            }

        } catch (SQLException e) {
            System.out.println("Error getting database metadata: " + e.getMessage());
        }

        System.out.println("\n=== Best Practices ===");
        System.out.println("1. Always use PreparedStatement to prevent SQL injection");
        System.out.println("2. Close resources in try-with-resources");
        System.out.println("3. Use connection pooling in production");
        System.out.println("4. Handle transactions appropriately");
        System.out.println("5. Use batch processing for bulk operations");

        System.out.println("\nJDBC Tutorial completed successfully!");
    }
}

