// String utilities to test
class StringUtils {
    public static String reverse(String str) {
        if (str == null) {
            return null;
        }
        return new StringBuilder(str).reverse().toString();
    }

    public static boolean isPalindrome(String str) {
        if (str == null) {
            return false;
        }
        String clean = str.replaceAll("[^a-zA-Z0-9]", "").toLowerCase();
        return clean.equals(reverse(clean));
    }

    public static int countVowels(String str) {
        if (str == null) {
            return 0;
        }
        return (int) str.toLowerCase().chars()
            .filter(c -> "aeiou".indexOf(c) != -1)
            .count();
    }
}

// Test class for StringUtils
class StringUtilsTest {

    @TestFactory
    @DisplayName("Dynamic tests for string reversal")
    Stream<DynamicTest> dynamicTestsForReverse() {
        List<String> inputs = Arrays.asList(
            "hello", "world", "java", "", "a", "racecar"
        );

        List<String> expected = Arrays.asList(
            "olleh", "dlrow", "avaj", "", "a", "racecar"
        );

        return IntStream.range(0, inputs.size())
            .mapToObj(i -> DynamicTest.dynamicTest(
                "Reverse: " + inputs.get(i),
                () -> assertEquals(expected.get(i), StringUtils.reverse(inputs.get(i)))
            ));
    }

    @ParameterizedTest
    @DisplayName("Test palindrome detection")
    @CsvSource({
        "racecar, true",
        "hello, false",
        "A man a plan a canal Panama, true",
        "12321, true",
        "'', false",
        "null, false"
    })
    void testIsPalindrome(String input, boolean expected) {
        if ("null".equals(input)) {
            assertEquals(expected, StringUtils.isPalindrome(null));
        } else {
            assertEquals(expected, StringUtils.isPalindrome(input));
        }
    }

    @Test
    @DisplayName("Test vowel counting")
    void testCountVowels() {
        assertEquals(2, StringUtils.countVowels("hello"));
        assertEquals(3, StringUtils.countVowels("beautiful"));
        assertEquals(0, StringUtils.countVowels("xyz"));
        assertEquals(0, StringUtils.countVowels(""));
        assertEquals(0, StringUtils.countVowels(null));
        assertEquals(5, StringUtils.countVowels("aeiou"));
        assertEquals(5, StringUtils.countVowels("AEIOU"));
    }
}

