            assertTrue(StringUtils.isPalindrome("racecar"));
            assertFalse(StringUtils.isPalindrome("hello"));
            assertTrue(StringUtils.isPalindrome("A man a plan a canal Panama"));
            System.out.println("✓ StringUtils.isPalindrome() tests passed");

        } catch (AssertionError e) {
            System.out.println("✗ StringUtils test failed: " + e.getMessage());
        }
    }

    private static void demonstrateTDD() {
        System.out.println("\nExample: Implementing a BankAccount class using TDD");

        // Step 1: Write test for BankAccount creation
        System.out.println("\nTest 1: BankAccount should have initial balance");
        // Test would check: new BankAccount(100).getBalance() == 100

        // Step 2: Write test for deposit
        System.out.println("Test 2: deposit() should increase balance");
        // Test would check: account.deposit(50) makes balance 150

        // Step 3: Write test for withdraw
        System.out.println("Test 3: withdraw() should decrease balance");
        // Test would check: account.withdraw(30) makes balance 70

        // Step 4: Write test for insufficient funds
        System.out.println("Test 4: withdraw() should throw exception for insufficient funds");
        // Test would check: account.withdraw(200) throws InsufficientFundsException

        System.out.println("\nAfter writing tests, implement BankAccount class to make tests pass.");
    }
}

