// ==================== BUILDER PATTERN ====================

// Product class
class Computer {
    private String CPU;
    private String RAM;
    private String storage;
    private String GPU;
    private boolean hasBluetooth;
    private boolean hasWiFi;

    private Computer(ComputerBuilder builder) {
        this.CPU = builder.CPU;
        this.RAM = builder.RAM;
        this.storage = builder.storage;
        this.GPU = builder.GPU;
        this.hasBluetooth = builder.hasBluetooth;
        this.hasWiFi = builder.hasWiFi;
    }

    @Override
    public String toString() {
        return "Computer[CPU=" + CPU + ", RAM=" + RAM + ", Storage=" + storage +
               ", GPU=" + GPU + ", Bluetooth=" + hasBluetooth + ", WiFi=" + hasWiFi + "]";
    }

    // Builder class
    public static class ComputerBuilder {
        private String CPU;
        private String RAM;
        private String storage;
        private String GPU;
        private boolean hasBluetooth = false;
        private boolean hasWiFi = false;

        // Required parameters
        public ComputerBuilder(String CPU, String RAM, String storage) {
            this.CPU = CPU;
            this.RAM = RAM;
            this.storage = storage;
        }

        public ComputerBuilder setGPU(String GPU) {
            this.GPU = GPU;
            return this;
        }

        public ComputerBuilder setBluetooth(boolean hasBluetooth) {
            this.hasBluetooth = hasBluetooth;
            return this;
        }

        public ComputerBuilder setWiFi(boolean hasWiFi) {
            this.hasWiFi = hasWiFi;
            return this;
        }

        public Computer build() {
            return new Computer(this);
        }
    }
}

// ==================== PROTOTYPE PATTERN ====================

// Prototype interface
interface Shape extends Cloneable {
    void draw();
    Shape clone();
}

// Concrete Prototypes
class Circle implements Shape {
    private String color;
    private int radius;

    public Circle(String color, int radius) {
        this.color = color;
        this.radius = radius;
    }

    @Override
    public void draw() {
        System.out.println("Drawing Circle [Color: " + color + ", Radius: " + radius + "]");
    }

    @Override
    public Shape clone() {
        try {
            return (Shape) super.clone();
        } catch (CloneNotSupportedException e) {
            throw new RuntimeException("Clone not supported", e);
        }
    }

    public void setColor(String color) {
        this.color = color;
    }

    public void setRadius(int radius) {
        this.radius = radius;
    }
}

class Rectangle implements Shape {
    private String color;
    private int width;
    private int height;

    public Rectangle(String color, int width, int height) {
        this.color = color;
        this.width = width;
        this.height = height;
    }

    @Override
    public void draw() {
        System.out.println("Drawing Rectangle [Color: " + color + ", Width: " + width + ", Height: " + height + "]");
    }

    @Override
    public Shape clone() {
        try {
            return (Shape) super.clone();
        } catch (CloneNotSupportedException e) {
            throw new RuntimeException("Clone not supported", e);
        }
    }

    public void setColor(String color) {
        this.color = color;
    }
}

// Prototype Registry
class ShapeRegistry {
    private static Map<String, Shape> shapes = new HashMap<>();

    static {
        shapes.put("defaultCircle", new Circle("Red", 10));
        shapes.put("defaultRectangle", new Rectangle("Blue", 20, 30));
    }

    public static void addShape(String key, Shape shape) {
        shapes.put(key, shape);
    }

    public static Shape getShape(String key) {
        Shape shape = shapes.get(key);
        return shape != null ? shape.clone() : null;
    }
}

// ==================== MAIN DEMONSTRATION ====================

public class CreationalPatternsDemo {
    public static void main(String[] args) {
        System.out.println("=== CREATIONAL DESIGN PATTERNS DEMONSTRATION ===\n");

        // 1. Singleton Pattern
        System.out.println("1. SINGLETON PATTERN:\n");

        System.out.println("Eager Singleton:");
        EagerSingleton eager1 = EagerSingleton.getInstance();
        EagerSingleton eager2 = EagerSingleton.getInstance();
        eager1.showMessage();
        System.out.println("Same instance? " + (eager1 == eager2));

        System.out.println("\nLazy Singleton:");
        LazySingleton lazy1 = LazySingleton.getInstance();
        LazySingleton lazy2 = LazySingleton.getInstance();
        lazy1.showMessage();
        System.out.println("Same instance? " + (lazy1 == lazy2));

        System.out.println("\nBill Pugh Singleton:");
        BillPughSingleton billPugh1 = BillPughSingleton.getInstance();
        BillPughSingleton billPugh2 = BillPughSingleton.getInstance();
        billPugh1.showMessage();
        System.out.println("Same instance? " + (billPugh1 == billPugh2));

        System.out.println("\nEnum Singleton:");
        EnumSingleton enum1 = EnumSingleton.INSTANCE;
        EnumSingleton enum2 = EnumSingleton.INSTANCE;
        enum1.showMessage();
        System.out.println("Same instance? " + (enum1 == enum2));

        // 2. Factory Method Pattern
        System.out.println("\n\n2. FACTORY METHOD PATTERN:\n");

        System.out.println("Using Factory Method:");
        NotificationFactory emailFactory = new EmailNotificationFactory();
        emailFactory.sendNotification("Hello via Email!");

        NotificationFactory smsFactory = new SMSNotificationFactory();
        smsFactory.sendNotification("Hello via SMS!");

        NotificationFactory pushFactory = new PushNotificationFactory();
        pushFactory.sendNotification("Hello via Push!");

        System.out.println("\nUsing Simple Factory:");
        Notification email = SimpleNotificationFactory.createNotification("email");
        email.send("Simple factory email");

        Notification sms = SimpleNotificationFactory.createNotification("sms");
        sms.send("Simple factory SMS");

        // 3. Abstract Factory Pattern
        System.out.println("\n\n3. ABSTRACT FACTORY PATTERN:\n");

        System.out.println("Windows Application:");
        Application windowsApp = new Application(new WindowsFactory());
        windowsApp.render();
        windowsApp.simulateUserInteraction();

        System.out.println("\nMacOS Application:");
        Application macOSApp = new Application(new MacOSFactory());
        macOSApp.render();
        macOSApp.simulateUserInteraction();

        // 4. Builder Pattern
        System.out.println("\n\n4. BUILDER PATTERN:\n");

        Computer gamingPC = new Computer.ComputerBuilder("Intel i9", "32GB", "1TB SSD")
            .setGPU("NVIDIA RTX 4080")
            .setBluetooth(true)
            .setWiFi(true)
            .build();

        System.out.println("Gaming PC: " + gamingPC);

        Computer officePC = new Computer.ComputerBuilder("Intel i5", "16GB", "512GB SSD")
            .setWiFi(true)
            .build();

        System.out.println("Office PC: " + officePC);

        // 5. Prototype Pattern
        System.out.println("\n\n5. PROTOTYPE PATTERN:\n");

        // Create original shapes
        Circle originalCircle = new Circle("Red", 10);
        Rectangle originalRectangle = new Rectangle("Blue", 20, 30);

        System.out.println("Original shapes:");
        originalCircle.draw();
        originalRectangle.draw();

        // Clone shapes
        Circle clonedCircle = (Circle) originalCircle.clone();
        Rectangle clonedRectangle = (Rectangle) originalRectangle.clone();

        // Modify clones
        clonedCircle.setColor("Green");
        clonedCircle.setRadius(15);
        clonedRectangle.setColor("Yellow");

        System.out.println("\nAfter cloning and modification:");
        System.out.println("Original Circle:");
        originalCircle.draw();
        System.out.println("Cloned Circle:");
        clonedCircle.draw();

        System.out.println("\nOriginal Rectangle:");
        originalRectangle.draw();
        System.out.println("Cloned Rectangle:");
        clonedRectangle.draw();

        // Using Prototype Registry
        System.out.println("\nUsing Prototype Registry:");
        Shape circleFromRegistry = ShapeRegistry.getShape("defaultCircle");
        Shape rectangleFromRegistry = ShapeRegistry.getShape("defaultRectangle");

        if (circleFromRegistry != null) {
            circleFromRegistry.draw();
        }

        if (rectangleFromRegistry != null) {
            rectangleFromRegistry.draw();
        }

        // Add new shape to registry
        Shape newCircle = new Circle("Purple", 25);
        ShapeRegistry.addShape("largePurpleCircle", newCircle);

        Shape largeCircle = ShapeRegistry.getShape("largePurpleCircle");
        if (largeCircle != null) {
            System.out.println("\nLarge circle from registry:");
            largeCircle.draw();
        }

        // Practical Example: Logger Singleton
        System.out.println("\n\n6. PRACTICAL EXAMPLE: LOGGER SINGLETON:\n");

        Logger logger1 = Logger.getInstance();
        Logger logger2 = Logger.getInstance();

        logger1.log("Application started");
        logger2.log("User logged in");
        logger1.log("Processing data...");
        logger2.log("Application exiting");

        logger1.printLogs();

        System.out.println("\n=== PATTERN COMPARISON ===");
        System.out.println("\nSingleton: Use when you need exactly one instance of a class");
        System.out.println("Factory Method: Use when you don't know the exact types of objects");
        System.out.println("Abstract Factory: Use when you need families of related objects");
        System.out.println("Builder: Use when object creation is complex with many parameters");
        System.out.println("Prototype: Use when object creation is expensive or complex");

        System.out.println("\nCreational Patterns Demonstration Completed!");
    }
}

// Practical Singleton Example: Logger
class Logger {
    private static Logger instance;
    private List<String> logs;

    private Logger() {
        logs = new ArrayList<>();
    }

    public static synchronized Logger getInstance() {
        if (instance == null) {
            instance = new Logger();
        }
        return instance;
    }

    public void log(String message) {
        String timestamp = LocalDateTime.now().toString();
        logs.add(timestamp + " - " + message);
    }

    public void printLogs() {
        System.out.println("\n=== APPLICATION LOGS ===");
        for (String log : logs) {
            System.out.println(log);
        }
    }
}

import java.util.*;
import java.io.*;

// ==================== ADAPTER PATTERN ====================

// Target interface (what client expects)
interface MediaPlayer {
    void play(String audioType, String fileName);
}

// Adaptee (existing functionality)
class AdvancedMediaPlayer {
    public void playVlc(String fileName) {
        System.out.println("Playing vlc file: " + fileName);
    }

    public void playMp4(String fileName) {
        System.out.println("Playing mp4 file: " + fileName);
    }
}

// Adapter (adapts AdvancedMediaPlayer to MediaPlayer interface)
class MediaAdapter implements MediaPlayer {
    private AdvancedMediaPlayer advancedMediaPlayer;

    public MediaAdapter() {
        this.advancedMediaPlayer = new AdvancedMediaPlayer();
    }

    @Override
    public void play(String audioType, String fileName) {
        if (audioType.equalsIgnoreCase("vlc")) {
            advancedMediaPlayer.playVlc(fileName);
        } else if (audioType.equalsIgnoreCase("mp4")) {
            advancedMediaPlayer.playMp4(fileName);
        }
    }
}

// Client using adapter
class AudioPlayer implements MediaPlayer {
    private MediaAdapter mediaAdapter;

    @Override
    public void play(String audioType, String fileName) {
        // Inbuilt support for mp3
        if (audioType.equalsIgnoreCase("mp3")) {
            System.out.println("Playing mp3 file: " + fileName);
        }
        // MediaAdapter provides support for other formats
        else if (audioType.equalsIgnoreCase("vlc") || audioType.equalsIgnoreCase("mp4")) {
            mediaAdapter = new MediaAdapter();
            mediaAdapter.play(audioType, fileName);
        } else {
            System.out.println("Invalid media type: " + audioType);
        }
    }
}

