        System.out.println("\n\n2. DECORATOR PATTERN:\n");

        Coffee simpleCoffee = new SimpleCoffee();
        System.out.println("Cost: " + simpleCoffee.getCost() + "; Description: " + simpleCoffee.getDescription());

        Coffee milkCoffee = new MilkDecorator(simpleCoffee);
        System.out.println("Cost: " + milkCoffee.getCost() + "; Description: " + milkCoffee.getDescription());

        Coffee sugarMilkCoffee = new SugarDecorator(milkCoffee);
        System.out.println("Cost: " + sugarMilkCoffee.getCost() + "; Description: " + sugarMilkCoffee.getDescription());

        Coffee deluxeCoffee = new WhippedCreamDecorator(new SugarDecorator(new MilkDecorator(new SimpleCoffee())));
        System.out.println("Cost: " + deluxeCoffee.getCost() + "; Description: " + deluxeCoffee.getDescription());

        // 3. Facade Pattern
        System.out.println("\n\n3. FACADE PATTERN:\n");

        ComputerFacade computer = new ComputerFacade();
        computer.start();

        // 4. Proxy Pattern
        System.out.println("\n\n4. PROXY PATTERN:\n");

        Image image1 = new ProxyImage("photo1.jpg");
        Image image2 = new ProxyImage("photo2.jpg");

        // Image will be loaded from disk only when displayed
        System.out.println("First display (will load from disk):");
        image1.display();

        System.out.println("\nSecond display (cached):");
        image1.display();

        System.out.println("\nThird display (new image, will load from disk):");
        image2.display();

        // 5. Composite Pattern
        System.out.println("\n\n5. COMPOSITE PATTERN:\n");

        // Create files
        File file1 = new File("document.txt", 1024);
        File file2 = new File("image.jpg", 2048);
        File file3 = new File("video.mp4", 4096);

        // Create directories
        Directory root = new Directory("Root");
        Directory documents = new Directory("Documents");
        Directory media = new Directory("Media");

        // Build structure
        documents.addComponent(file1);
        media.addComponent(file2);
        media.addComponent(file3);

        root.addComponent(documents);
        root.addComponent(media);

        // Show details
        root.showDetails();
        System.out.println("\nTotal size of root: " + root.getSize() + " bytes");

        // 6. Bridge Pattern
        System.out.println("\n\n6. BRIDGE PATTERN:\n");

        Color red = new Red();
        Color blue = new Blue();
        Color green = new Green();

        Shape redCircle = new Circle(red);
        Shape blueCircle = new Circle(blue);
        Shape greenSquare = new Square(green);

        System.out.println(redCircle.draw());
        System.out.println(blueCircle.draw());
        System.out.println(greenSquare.draw());

        // 7. Flyweight Pattern
        System.out.println("\n\n7. FLYWEIGHT PATTERN:\n");

        Forest forest = new Forest();

        // Plant many trees - notice how TreeTypes are reused
        forest.plantTree(1, 2, "Oak", "Green", "Rough");
        forest.plantTree(3, 4, "Pine", "Dark Green", "Smooth");
        forest.plantTree(5, 6, "Oak", "Green", "Rough"); // Reusing Oak type
        forest.plantTree(7, 8, "Maple", "Red", "Smooth");
        forest.plantTree(9, 10, "Pine", "Dark Green", "Smooth"); // Reusing Pine type
        forest.plantTree(11, 12, "Oak", "Green", "Rough"); // Reusing Oak type again

        System.out.println("\nDrawing forest:");
        forest.draw();

        // Practical Examples
        System.out.println("\n\n8. PRACTICAL EXAMPLES:\n");

        // Adapter: Legacy System Integration
        System.out.println("Adapter Example - Legacy System Integration:");
        System.out.println("Useful when integrating new code with old systems");

        // Decorator: Java I/O Streams
        System.out.println("\nDecorator Example - Java I/O Streams:");
        System.out.println("BufferedReader(new FileReader("file.txt")) uses decorator pattern");

        // Facade: JDBC
        System.out.println("\nFacade Example - JDBC:");
        System.out.println("DriverManager.getConnection() provides simple interface to complex database operations");

        // Proxy: Virtual Proxy
        System.out.println("\nProxy Example - Lazy Initialization:");
        System.out.println("Useful for expensive object creation (like large images)");

        // Composite: GUI Components
        System.out.println("\nComposite Example - GUI Components:");
        System.out.println("Java Swing/AWT uses composite pattern for containers and components");

        // Bridge: Database Drivers
        System.out.println("\nBridge Example - Database Drivers:");
        System.out.println("JDBC uses bridge pattern to separate abstraction from implementation");

        // Flyweight: String Pool
        System.out.println("\nFlyweight Example - String Pool:");
        System.out.println("Java String pool is a classic example of flyweight pattern");

        System.out.println("\n=== PATTERN COMPARISON ===");
        System.out.println("\nAdapter: Makes incompatible interfaces work together");
        System.out.println("Decorator: Adds responsibilities to objects dynamically");
        System.out.println("Facade: Provides simple interface to complex subsystem");
        System.out.println("Proxy: Controls access to another object");
        System.out.println("Composite: Treats individual and composite objects uniformly");
        System.out.println("Bridge: Separates abstraction from implementation");
        System.out.println("Flyweight: Shares common parts to support large numbers of objects");

        System.out.println("\nStructural Patterns Demonstration Completed!");
    }
}

import java.util.*;

// ==================== OBSERVER PATTERN ====================

// Observer interface
interface Observer {
    void update(String message);
}

// Subject interface
interface Subject {
    void registerObserver(Observer observer);
    void removeObserver(Observer observer);
    void notifyObservers();
}

// Concrete Subject
class NewsAgency implements Subject {
    private List<Observer> observers;
    private String news;

    public NewsAgency() {
        this.observers = new ArrayList<>();
    }

    @Override
    public void registerObserver(Observer observer) {
        observers.add(observer);
    }

    @Override
    public void removeObserver(Observer observer) {
        observers.remove(observer);
    }

    @Override
    public void notifyObservers() {
        for (Observer observer : observers) {
            observer.update(news);
        }
    }

    public void setNews(String news) {
        this.news = news;
        notifyObservers();
    }
}

// Concrete Observers
class NewsChannel implements Observer {
    private String name;
    private String latestNews;

    public NewsChannel(String name) {
        this.name = name;
    }

    @Override
    public void update(String news) {
        this.latestNews = news;
        display();
    }

    public void display() {
        System.out.println(name + " received news: " + latestNews);
    }
}

// ==================== STRATEGY PATTERN ====================

// Strategy interface
interface PaymentStrategy {
    void pay(double amount);
}

// Concrete Strategies
class CreditCardPayment implements PaymentStrategy {
    private String name;
    private String cardNumber;
    private String cvv;

    public CreditCardPayment(String name, String cardNumber, String cvv) {
        this.name = name;
        this.cardNumber = cardNumber;
        this.cvv = cvv;
    }

    @Override
    public void pay(double amount) {
        System.out.println("Paid $" + amount + " using credit card ending with " + 
                         cardNumber.substring(cardNumber.length() - 4));
    }
}

class PayPalPayment implements PaymentStrategy {
    private String email;

    public PayPalPayment(String email) {
        this.email = email;
    }

    @Override
    public void pay(double amount) {
        System.out.println("Paid $" + amount + " using PayPal account " + email);
    }
}

class BitcoinPayment implements PaymentStrategy {
    private String walletAddress;

    public BitcoinPayment(String walletAddress) {
        this.walletAddress = walletAddress;
    }

    @Override
    public void pay(double amount) {
        System.out.println("Paid $" + amount + " using Bitcoin wallet " + 
                         walletAddress.substring(0, 8) + "...");
    }
}

// Context
class ShoppingCart {
    private List<String> items;
    private PaymentStrategy paymentStrategy;

    public ShoppingCart() {
        this.items = new ArrayList<>();
    }

    public void addItem(String item) {
        items.add(item);
    }

    public void setPaymentStrategy(PaymentStrategy paymentStrategy) {
        this.paymentStrategy = paymentStrategy;
    }

    public void checkout(double amount) {
        if (paymentStrategy == null) {
            System.out.println("Please set payment strategy first!");
            return;
        }
        System.out.println("\nCheckout items: " + items);
        paymentStrategy.pay(amount);
        items.clear();
    }
}

// ==================== COMMAND PATTERN ====================

// Command interface
interface Command {
    void execute();
    void undo();
}

// Receiver
class Light {
    private boolean isOn = false;

    public void turnOn() {
        isOn = true;
        System.out.println("Light is ON");
    }

    public void turnOff() {
        isOn = false;
        System.out.println("Light is OFF");
    }

    public boolean isOn() {
        return isOn;
    }
}

// Concrete Commands
class TurnOnLightCommand implements Command {
    private Light light;

    public TurnOnLightCommand(Light light) {
        this.light = light;
    }

    @Override
    public void execute() {
        light.turnOn();
    }

    @Override
    public void undo() {
        light.turnOff();
    }
}

class TurnOffLightCommand implements Command {
    private Light light;

    public TurnOffLightCommand(Light light) {
        this.light = light;
    }

    @Override
    public void execute() {
        light.turnOff();
    }

    @Override
    public void undo() {
        light.turnOn();
    }
}

// Invoker
class RemoteControl {
    private Command command;
    private Command lastCommand;

    public void setCommand(Command command) {
        this.command = command;
    }

    public void pressButton() {
        if (command != null) {
            lastCommand = command;
            command.execute();
        }
    }

    public void pressUndo() {
        if (lastCommand != null) {
            lastCommand.undo();
            lastCommand = null;
        }
    }
}

// ==================== ITERATOR PATTERN ====================

// Iterator interface
interface Iterator<T> {
    boolean hasNext();
    T next();
}

// Aggregate interface
interface Container<T> {
    Iterator<T> getIterator();
}

// Concrete Aggregate
class NameRepository implements Container<String> {
    private String[] names = {"Alice", "Bob", "Charlie", "Diana", "Edward"};

    @Override
    public Iterator<String> getIterator() {
        return new NameIterator();
    }

    // Concrete Iterator
    private class NameIterator implements Iterator<String> {
        private int index = 0;

        @Override
        public boolean hasNext() {
            return index < names.length;
        }

        @Override
        public String next() {
            if (hasNext()) {
                return names[index++];
            }
            return null;
        }
    }
}

// ==================== STATE PATTERN ====================

// State interface
interface VendingMachineState {
    void insertCoin();
    void selectProduct();
    void dispense();
}

// Concrete States
class NoCoinState implements VendingMachineState {
    private VendingMachine vendingMachine;

    public NoCoinState(VendingMachine vendingMachine) {
        this.vendingMachine = vendingMachine;
    }

    @Override
    public void insertCoin() {
        System.out.println("Coin inserted");
        vendingMachine.setState(vendingMachine.getHasCoinState());
    }

    @Override
    public void selectProduct() {
        System.out.println("Please insert a coin first");
    }

    @Override
    public void dispense() {
        System.out.println("Please insert a coin first");
    }
}

class HasCoinState implements VendingMachineState {
    private VendingMachine vendingMachine;

    public HasCoinState(VendingMachine vendingMachine) {
        this.vendingMachine = vendingMachine;
    }

    @Override
    public void insertCoin() {
        System.out.println("Coin already inserted");
    }

    @Override
    public void selectProduct() {
        System.out.println("Product selected");
        vendingMachine.setState(vendingMachine.getSoldState());
    }

    @Override
    public void dispense() {
        System.out.println("Please select a product first");
    }
}

class SoldState implements VendingMachineState {
    private VendingMachine vendingMachine;

    public SoldState(VendingMachine vendingMachine) {
        this.vendingMachine = vendingMachine;
    }

    @Override
    public void insertCoin() {
        System.out.println("Please wait, dispensing product");
    }

    @Override
    public void selectProduct() {
        System.out.println("Product already selected");
    }

    @Override
    public void dispense() {
        System.out.println("Product dispensed");
        vendingMachine.setState(vendingMachine.getNoCoinState());
    }
}

// Context
class VendingMachine {
    private VendingMachineState noCoinState;
    private VendingMachineState hasCoinState;
    private VendingMachineState soldState;

    private VendingMachineState currentState;

    public VendingMachine() {
        noCoinState = new NoCoinState(this);
        hasCoinState = new HasCoinState(this);
        soldState = new SoldState(this);

        currentState = noCoinState; // Initial state
    }

    public void setState(VendingMachineState state) {
        this.currentState = state;
    }

    public VendingMachineState getNoCoinState() {
        return noCoinState;
    }

    public VendingMachineState getHasCoinState() {
        return hasCoinState;
    }

    public VendingMachineState getSoldState() {
        return soldState;
    }

    // Delegate methods to current state
    public void insertCoin() {
        currentState.insertCoin();
    }

    public void selectProduct() {
        currentState.selectProduct();
    }

    public void dispense() {
        currentState.dispense();
    }
}

// ==================== TEMPLATE METHOD PATTERN ====================

// Abstract class with template method
abstract class DataProcessor {
    // Template method - defines the algorithm skeleton
    public final void process() {
        readData();
        processData();
        saveData();
    }

    // Abstract methods to be implemented by subclasses
    abstract void readData();
    abstract void processData();

    // Hook method (can be overridden)
    void saveData() {
        System.out.println("Saving data to database...");
    }
}

// Concrete implementations
class CSVDataProcessor extends DataProcessor {
    @Override
    void readData() {
        System.out.println("Reading data from CSV file...");
    }

    @Override
    void processData() {
        System.out.println("Processing CSV data...");
    }
}

class XMLDataProcessor extends DataProcessor {
    @Override
    void readData() {
        System.out.println("Reading data from XML file...");
    }

    @Override
    void processData() {
        System.out.println("Processing XML data...");
    }

    @Override
    void saveData() {
        System.out.println("Saving processed XML data to cloud storage...");
    }
}

// ==================== VISITOR PATTERN ====================

// Element interface
interface ComputerPart {
    void accept(ComputerPartVisitor visitor);
}

// Concrete Elements
class Keyboard implements ComputerPart {
    @Override
    public void accept(ComputerPartVisitor visitor) {
        visitor.visit(this);
    }
}

class Monitor implements ComputerPart {
    @Override
    public void accept(ComputerPartVisitor visitor) {
        visitor.visit(this);
    }
}

class Mouse implements ComputerPart {
    @Override
    public void accept(ComputerPartVisitor visitor) {
        visitor.visit(this);
    }
}

class Computer implements ComputerPart {
    private ComputerPart[] parts;

    public Computer() {
        parts = new ComputerPart[] {
            new Keyboard(),
            new Monitor(),
            new Mouse()
        };
    }

    @Override
    public void accept(ComputerPartVisitor visitor) {
        for (ComputerPart part : parts) {
            part.accept(visitor);
        }
        visitor.visit(this);
    }
}

// Visitor interface
interface ComputerPartVisitor {
    void visit(Keyboard keyboard);
    void visit(Monitor monitor);
    void visit(Mouse mouse);
    void visit(Computer computer);
}

// Concrete Visitor
class ComputerPartDisplayVisitor implements ComputerPartVisitor {
    @Override
    public void visit(Keyboard keyboard) {
        System.out.println("Displaying Keyboard");
    }

    @Override
    public void visit(Monitor monitor) {
        System.out.println("Displaying Monitor");
    }

    @Override
    public void visit(Mouse mouse) {
        System.out.println("Displaying Mouse");
    }

    @Override
    public void visit(Computer computer) {
        System.out.println("Displaying Computer");
    }
}

