        // Chain of Responsibility
        System.out.println("Chain of Responsibility:");
        System.out.println("Passes request along a chain of handlers");

        // Mediator
        System.out.println("\nMediator:");
        System.out.println("Reduces coupling between communicating objects");

        // Memento
        System.out.println("\nMemento:");
        System.out.println("Captures and restores object state");

        // Practical Examples
        System.out.println("\n\n9. PRACTICAL EXAMPLES:\n");

        System.out.println("Observer: Event listeners in GUI frameworks");
        System.out.println("Strategy: Sorting algorithms (Collections.sort() with Comparator)");
        System.out.println("Command: Undo/redo functionality in text editors");
        System.out.println("Iterator: Java Collections Framework iterators");
        System.out.println("State: TCP connection states");
        System.out.println("Template Method: Servlet lifecycle");
        System.out.println("Visitor: Java annotation processing");

        System.out.println("\n=== PATTERN COMPARISON ===");
        System.out.println("\nObserver: One-to-many dependency between objects");
        System.out.println("Strategy: Family of algorithms, interchangeable");
        System.out.println("Command: Encapsulates request as an object");
        System.out.println("Iterator: Sequentially access elements of collection");
        System.out.println("State: Object behavior changes with its state");
        System.out.println("Template Method: Defines algorithm skeleton");
        System.out.println("Visitor: Separates algorithm from object structure");

        System.out.println("\nBehavioral Patterns Demonstration Completed!");
    }
}

import java.net.*;
import java.io.*;
import java.util.*;

public class NetworkingTutorial {

    // ==================== TCP CLIENT/SERVER ====================

    static class TCPServer {
        public static void startServer(int port) {
            try (ServerSocket serverSocket = new ServerSocket(port)) {
                System.out.println("TCP Server started on port " + port);

                while (true) {
                    Socket clientSocket = serverSocket.accept();
                    System.out.println("Client connected: " + clientSocket.getInetAddress());

                    // Handle client in a new thread
                    new Thread(() -> handleClient(clientSocket)).start();
                }
            } catch (IOException e) {
                System.out.println("Server error: " + e.getMessage());
            }
        }

        private static void handleClient(Socket clientSocket) {
            try (BufferedReader in = new BufferedReader(
                     new InputStreamReader(clientSocket.getInputStream()));
                 PrintWriter out = new PrintWriter(clientSocket.getOutputStream(), true)) {

                String inputLine;
                while ((inputLine = in.readLine()) != null) {
                    System.out.println("Received from client: " + inputLine);

                    // Echo back to client
                    out.println("Echo: " + inputLine);

                    if (inputLine.equalsIgnoreCase("exit")) {
                        break;
                    }
                }

                System.out.println("Client disconnected: " + clientSocket.getInetAddress());
            } catch (IOException e) {
                System.out.println("Client handling error: " + e.getMessage());
            } finally {
                try {
                    clientSocket.close();
                } catch (IOException e) {
                    System.out.println("Error closing client socket: " + e.getMessage());
                }
            }
        }
    }

    static class TCPClient {
        public static void startClient(String host, int port) {
            try (Socket socket = new Socket(host, port);
                 BufferedReader in = new BufferedReader(
                     new InputStreamReader(socket.getInputStream()));
                 PrintWriter out = new PrintWriter(socket.getOutputStream(), true);
                 BufferedReader userInput = new BufferedReader(
                     new InputStreamReader(System.in))) {

                System.out.println("Connected to server " + host + ":" + port);
                System.out.println("Type 'exit' to quit\n");

                // Thread to read server responses
                Thread readerThread = new Thread(() -> {
                    try {
                        String serverResponse;
                        while ((serverResponse = in.readLine()) != null) {
                            System.out.println("Server: " + serverResponse);
                        }
                    } catch (IOException e) {
                        System.out.println("Connection closed");
                    }
                });
                readerThread.start();

                // Read user input and send to server
                String userInputLine;
                while ((userInputLine = userInput.readLine()) != null) {
                    out.println(userInputLine);
                    if (userInputLine.equalsIgnoreCase("exit")) {
                        break;
                    }
                }

                readerThread.join();
            } catch (IOException | InterruptedException e) {
                System.out.println("Client error: " + e.getMessage());
            }
        }
    }

    // ==================== UDP CLIENT/SERVER ====================

    static class UDPServer {
        public static void startServer(int port) {
            try (DatagramSocket socket = new DatagramSocket(port)) {
                System.out.println("UDP Server started on port " + port);
                byte[] buffer = new byte[1024];

                while (true) {
                    DatagramPacket packet = new DatagramPacket(buffer, buffer.length);
                    socket.receive(packet);

                    String received = new String(packet.getData(), 0, packet.getLength());
                    InetAddress clientAddress = packet.getAddress();
                    int clientPort = packet.getPort();

                    System.out.println("Received from " + clientAddress + ":" + clientPort + ": " + received);

                    // Echo back
                    String response = "UDP Echo: " + received;
                    byte[] responseData = response.getBytes();
                    DatagramPacket responsePacket = new DatagramPacket(
                        responseData, responseData.length, clientAddress, clientPort);
                    socket.send(responsePacket);
                }
            } catch (IOException e) {
                System.out.println("UDP Server error: " + e.getMessage());
            }
        }
    }

    static class UDPClient {
        public static void startClient(String host, int port) {
            try (DatagramSocket socket = new DatagramSocket();
                 BufferedReader userInput = new BufferedReader(
                     new InputStreamReader(System.in))) {

                InetAddress serverAddress = InetAddress.getByName(host);
                System.out.println("UDP Client started. Type 'exit' to quit\n");

                while (true) {
                    System.out.print("Enter message: ");
                    String message = userInput.readLine();

                    if (message.equalsIgnoreCase("exit")) {
                        break;
                    }

                    // Send message
                    byte[] sendData = message.getBytes();
                    DatagramPacket sendPacket = new DatagramPacket(
                        sendData, sendData.length, serverAddress, port);
                    socket.send(sendPacket);

                    // Receive response
                    byte[] receiveData = new byte[1024];
                    DatagramPacket receivePacket = new DatagramPacket(receiveData, receiveData.length);
                    socket.receive(receivePacket);

                    String response = new String(receivePacket.getData(), 0, receivePacket.getLength());
                    System.out.println("Server response: " + response);
                }
            } catch (IOException e) {
                System.out.println("UDP Client error: " + e.getMessage());
            }
        }
    }

    // ==================== HTTP CLIENT ====================

    static class SimpleHttpClient {
        public static void makeHttpGetRequest(String urlString) {
            try {
                URL url = new URL(urlString);
                HttpURLConnection connection = (HttpURLConnection) url.openConnection();

                // Set request method
                connection.setRequestMethod("GET");

                // Set request headers
                connection.setRequestProperty("User-Agent", "Java-HTTP-Client");
                connection.setRequestProperty("Accept", "text/html");

                // Get response code
                int responseCode = connection.getResponseCode();
                System.out.println("Response Code: " + responseCode);

                // Get response headers
                Map<String, List<String>> headers = connection.getHeaderFields();
                System.out.println("\nResponse Headers:");
                for (Map.Entry<String, List<String>> entry : headers.entrySet()) {
                    System.out.println(entry.getKey() + ": " + entry.getValue());
                }

                // Read response body
                System.out.println("\nResponse Body (first 500 chars):");
                try (BufferedReader in = new BufferedReader(
                         new InputStreamReader(connection.getInputStream()))) {
                    String inputLine;
                    StringBuilder response = new StringBuilder();
                    int charCount = 0;

                    while ((inputLine = in.readLine()) != null && charCount < 500) {
                        response.append(inputLine).append("\n");
                        charCount += inputLine.length();
                    }
                    System.out.println(response.toString());
                }

                connection.disconnect();

            } catch (IOException e) {
                System.out.println("HTTP Request error: " + e.getMessage());
            }
        }

        public static void makeHttpPostRequest(String urlString, String postData) {
            try {
                URL url = new URL(urlString);
                HttpURLConnection connection = (HttpURLConnection) url.openConnection();

                // Set request method and properties
                connection.setRequestMethod("POST");
                connection.setRequestProperty("Content-Type", "application/x-www-form-urlencoded");
                connection.setRequestProperty("Content-Length", String.valueOf(postData.length()));
                connection.setDoOutput(true);

                // Write post data
                try (DataOutputStream out = new DataOutputStream(connection.getOutputStream())) {
                    out.writeBytes(postData);
                    out.flush();
                }

                // Get response
                int responseCode = connection.getResponseCode();
                System.out.println("POST Response Code: " + responseCode);

                // Read response
                try (BufferedReader in = new BufferedReader(
                         new InputStreamReader(connection.getInputStream()))) {
                    String inputLine;
                    StringBuilder response = new StringBuilder();

                    while ((inputLine = in.readLine()) != null) {
                        response.append(inputLine);
                    }
                    System.out.println("POST Response: " + response.toString());
                }

                connection.disconnect();

            } catch (IOException e) {
                System.out.println("HTTP POST Request error: " + e.getMessage());
            }
        }
    }

