    // ==================== MULTICAST EXAMPLE ====================

    static class MulticastClient {
        public static void startMulticastReceiver(String multicastGroup, int port) {
            try (MulticastSocket socket = new MulticastSocket(port)) {
                InetAddress group = InetAddress.getByName(multicastGroup);
                socket.joinGroup(group);

                System.out.println("Multicast receiver joined group: " + multicastGroup);

                byte[] buffer = new byte[1024];
                while (true) {
                    DatagramPacket packet = new DatagramPacket(buffer, buffer.length);
                    socket.receive(packet);

                    String message = new String(packet.getData(), 0, packet.getLength());
                    System.out.println("Multicast message from " + packet.getAddress() + ": " + message);
                }

            } catch (IOException e) {
                System.out.println("Multicast error: " + e.getMessage());
            }
        }

        public static void sendMulticastMessage(String multicastGroup, int port, String message) {
            try (MulticastSocket socket = new MulticastSocket()) {
                InetAddress group = InetAddress.getByName(multicastGroup);
                byte[] buffer = message.getBytes();

                DatagramPacket packet = new DatagramPacket(buffer, buffer.length, group, port);
                socket.send(packet);
                System.out.println("Multicast message sent to group " + multicastGroup);

            } catch (IOException e) {
                System.out.println("Multicast send error: " + e.getMessage());
            }
        }
    }

