// Custom annotation for demonstration
@Retention(RetentionPolicy.RUNTIME)
@Target({ElementType.TYPE, ElementType.METHOD, ElementType.FIELD})
@interface CustomAnnotation {
    String value() default "";
    int version() default 1;
}

// Sample class for reflection
@CustomAnnotation(value = "SampleClass", version = 2)
class SampleClass {
    private String privateField = "Private Value";
    public String publicField = "Public Value";
    protected String protectedField = "Protected Value";
    String defaultField = "Default Value";

    public SampleClass() {
        System.out.println("Default constructor called");
    }

    public SampleClass(String value) {
        this.publicField = value;
        System.out.println("Parameterized constructor called with: " + value);
    }

    private SampleClass(String value1, String value2) {
        this.publicField = value1 + " " + value2;
        System.out.println("Private constructor called");
    }

    public void publicMethod() {
        System.out.println("Public method called");
    }

    private void privateMethod() {
        System.out.println("Private method called");
    }

    @CustomAnnotation(value = "annotatedMethod", version = 3)
    public void annotatedMethod() {
        System.out.println("Annotated method called");
    }

    public String methodWithParams(String param1, int param2) {
        return "Parameters received: " + param1 + ", " + param2;
    }

    public static void staticMethod() {
        System.out.println("Static method called");
    }
}

