    public static void demonstrateDynamicProxy() {
        System.out.println("\n=== DYNAMIC PROXY ===");

        SampleInterface realObject = new AnotherClass();

        // Create proxy
        SampleInterface proxy = (SampleInterface) Proxy.newProxyInstance(
            SampleInterface.class.getClassLoader(),
            new Class[]{SampleInterface.class},
            new InvocationHandler() {
                @Override
                public Object invoke(Object proxy, Method method, Object[] args) throws Throwable {
                    System.out.println("Before method: " + method.getName());
                    Object result = method.invoke(realObject, args);
