    // 12. Simple Dependency Injection (Practical Example)
    public static class SimpleContainer {
        private Map<Class<?>, Object> instances = new HashMap<>();

        public void register(Class<?> clazz, Object instance) {
            instances.put(clazz, instance);
        }

        public <T> T getInstance(Class<T> clazz) throws Exception {
            if (instances.containsKey(clazz)) {
                return clazz.cast(instances.get(clazz));
            }

            // Create new instance with dependency injection
            Constructor<?>[] constructors = clazz.getConstructors();
            if (constructors.length == 0) {
                throw new RuntimeException("No public constructor found for " + clazz.getName());
            }

            // Use first constructor
            Constructor<?> constructor = constructors[0];
            Class<?>[] paramTypes = constructor.getParameterTypes();
            Object[] params = new Object[paramTypes.length];

            for (int i = 0; i < paramTypes.length; i++) {
                params[i] = getInstance(paramTypes[i]);
            }

            T instance = clazz.cast(constructor.newInstance(params));
            instances.put(clazz, instance);
            return instance;
        }
    }

