    // 13. Reflection Performance Considerations
    public static void demonstratePerformance() throws Exception {
        System.out.println("\n=== REFLECTION PERFORMANCE ===");

        SampleClass obj = new SampleClass();
        Class<?> clazz = obj.getClass();
        Method method = clazz.getMethod("publicMethod");

        // Direct invocation
        long startTime = System.nanoTime();
        for (int i = 0; i < 10000; i++) {
            obj.publicMethod();
        }
        long directTime = System.nanoTime() - startTime;

        // Reflection invocation
        startTime = System.nanoTime();
        for (int i = 0; i < 10000; i++) {
            method.invoke(obj);
        }
        long reflectionTime = System.nanoTime() - startTime;

        System.out.printf("Direct invocation: %,d ns\n", directTime);
        System.out.printf("Reflection invocation: %,d ns\n", reflectionTime);
        System.out.printf("Reflection is %.1f times slower\n", 
                         (double) reflectionTime / directTime);
    }

    // 14. Security Considerations
    public static void demonstrateSecurity() {
        System.out.println("\n=== SECURITY CONSIDERATIONS ===");

        System.out.println("1. Reflection can break encapsulation");
        System.out.println("2. SecurityManager can restrict reflection");
        System.out.println("3. Use setAccessible(true) judiciously");
        System.out.println("4. Consider MethodHandles for better performance");
    }

    // Main demonstration method
    public static void main(String[] args) {
        System.out.println("=== JAVA REFLECTION TUTORIAL ===\n");

        try {
            // 1. Basic Class Information
            demonstrateClassInfo(SampleClass.class);

            // 2. Field Information
