            // 3. Method Information
            demonstrateMethods(SampleClass.class);

            // 4. Constructor Information
            demonstrateConstructors(SampleClass.class);

            // 5. Field Operations
            demonstrateFieldOperations();

            // 6. Method Operations
            demonstrateMethodOperations();

            // 7. Constructor Operations
            demonstrateConstructorOperations();

            // 8. Annotation Processing
            demonstrateAnnotations(SampleClass.class);

            // 9. Array Operations
            demonstrateArrays();

            // 10. Dynamic Proxy
            demonstrateDynamicProxy();

            // 11. Object Printer Example
            SampleClass sample = new SampleClass("Test");
            ObjectPrinter.printObject(sample);

            // 12. Dependency Injection Example
            System.out.println("\n=== DEPENDENCY INJECTION EXAMPLE ===");
            SimpleContainer container = new SimpleContainer();
            container.register(Service.class, new Service());
            Controller controller = container.getInstance(Controller.class);
            controller.handleRequest();

            // 13. Performance Considerations
            demonstratePerformance();

            // 14. Security Considerations
            demonstrateSecurity();

            System.out.println("\n=== PRACTICAL USE CASES ===");
            System.out.println("1. Frameworks (Spring, Hibernate)");
            System.out.println("2. Serialization/Deserialization");
            System.out.println("3. Testing frameworks (JUnit)");
            System.out.println("4. Code analysis tools");
            System.out.println("5. Dynamic class loading");

            System.out.println("\n=== BEST PRACTICES ===");
            System.out.println("1. Use reflection sparingly");
            System.out.println("2. Cache reflective objects");
            System.out.println("3. Handle exceptions properly");
            System.out.println("4. Consider security implications");
            System.out.println("5. Use MethodHandles for better performance");

