// ==================== MAIN APPLICATION: LIBRARY MANAGEMENT SYSTEM ====================

// Enum for book status
enum BookStatus {
    AVAILABLE, BORROWED, RESERVED, UNDER_MAINTENANCE
}

// Enum for user type
enum UserType {
    STUDENT, FACULTY, STAFF, GUEST
}

// Custom exception for library operations
class LibraryException extends Exception {
    public LibraryException(String message) {
        super(message);
    }
}

// ==================== ENTITY CLASSES ====================

// Base Entity class
abstract class Entity {
    protected String id;
    protected String name;
    protected LocalDateTime createdAt;

    public Entity(String id, String name) {
        this.id = id;
        this.name = name;
        this.createdAt = LocalDateTime.now();
    }

    public String getId() { return id; }
    public String getName() { return name; }
    public LocalDateTime getCreatedAt() { return createdAt; }

    @Override
    public String toString() {
        return String.format("%s[id=%s, name='%s']", 
                           getClass().getSimpleName(), id, name);
    }
}

// Book class
class Book extends Entity {
    private String author;
    private String isbn;
    private int publicationYear;
    private String genre;
    private BookStatus status;
    private int totalCopies;
    private int availableCopies;

    public Book(String id, String title, String author, String isbn, 
                int publicationYear, String genre, int totalCopies) {
        super(id, title);
        this.author = author;
        this.isbn = isbn;
        this.publicationYear = publicationYear;
        this.genre = genre;
        this.status = BookStatus.AVAILABLE;
        this.totalCopies = totalCopies;
        this.availableCopies = totalCopies;
    }

    // Getters and setters
    public String getAuthor() { return author; }
    public String getIsbn() { return isbn; }
    public int getPublicationYear() { return publicationYear; }
    public String getGenre() { return genre; }
    public BookStatus getStatus() { return status; }
    public int getTotalCopies() { return totalCopies; }
    public int getAvailableCopies() { return availableCopies; }

    public void setStatus(BookStatus status) { this.status = status; }
    public void setAvailableCopies(int availableCopies) { 
        this.availableCopies = availableCopies; 
    }

    public boolean isAvailable() {
        return status == BookStatus.AVAILABLE && availableCopies > 0;
    }

    public void borrowCopy() throws LibraryException {
        if (!isAvailable()) {
            throw new LibraryException("Book is not available for borrowing");
        }
        availableCopies--;
        if (availableCopies == 0) {
            status = BookStatus.BORROWED;
        }
    }

    public void returnCopy() {
        availableCopies++;
        if (availableCopies > 0) {
            status = BookStatus.AVAILABLE;
        }
    }

    @Override
    public String toString() {
        return String.format("Book[id=%s, title='%s', author='%s', status=%s, available=%d/%d]",
                           id, name, author, status, availableCopies, totalCopies);
    }
}

// User class
class User extends Entity {
    private UserType type;
    private String email;
    private String phone;
    private List<Book> borrowedBooks;
    private int maxBorrowLimit;

    public User(String id, String name, UserType type, String email, String phone) {
        super(id, name);
        this.type = type;
        this.email = email;
        this.phone = phone;
        this.borrowedBooks = new ArrayList<>();
        this.maxBorrowLimit = getBorrowLimitByType(type);
    }

    private int getBorrowLimitByType(UserType type) {
        switch (type) {
            case STUDENT: return 5;
            case FACULTY: return 10;
            case STAFF: return 7;
            case GUEST: return 2;
            default: return 3;
        }
    }

    // Getters
    public UserType getType() { return type; }
    public String getEmail() { return email; }
    public String getPhone() { return phone; }
    public List<Book> getBorrowedBooks() { return new ArrayList<>(borrowedBooks); }
    public int getMaxBorrowLimit() { return maxBorrowLimit; }
    public int getCurrentBorrowCount() { return borrowedBooks.size(); }

    public boolean canBorrowMore() {
        return borrowedBooks.size() < maxBorrowLimit;
    }

    public void borrowBook(Book book) throws LibraryException {
        if (!canBorrowMore()) {
            throw new LibraryException("User has reached borrow limit");
        }
        borrowedBooks.add(book);
    }

    public void returnBook(Book book) {
        borrowedBooks.remove(book);
    }

    @Override
    public String toString() {
        return String.format("User[id=%s, name='%s', type=%s, borrowed=%d/%d]",
                           id, name, type, borrowedBooks.size(), maxBorrowLimit);
    }
}

// Transaction record
class Transaction {
    private String id;
    private User user;
    private Book book;
    private LocalDateTime borrowDate;
    private LocalDateTime dueDate;
    private LocalDateTime returnDate;
    private double fineAmount;

    public Transaction(User user, Book book) {
        this.id = UUID.randomUUID().toString();
        this.user = user;
        this.book = book;
        this.borrowDate = LocalDateTime.now();
        this.dueDate = borrowDate.plusDays(getBorrowPeriod(user.getType()));
        this.fineAmount = 0.0;
    }

    private int getBorrowPeriod(UserType type) {
        switch (type) {
            case STUDENT: return 14;
            case FACULTY: return 30;
            case STAFF: return 21;
            case GUEST: return 7;
            default: return 14;
        }
    }

    // Getters
    public String getId() { return id; }
    public User getUser() { return user; }
    public Book getBook() { return book; }
    public LocalDateTime getBorrowDate() { return borrowDate; }
    public LocalDateTime getDueDate() { return dueDate; }
    public LocalDateTime getReturnDate() { return returnDate; }
    public double getFineAmount() { return fineAmount; }

    public void returnBook() {
        this.returnDate = LocalDateTime.now();
        calculateFine();
    }

    private void calculateFine() {
        if (returnDate.isAfter(dueDate)) {
            long daysLate = Duration.between(dueDate, returnDate).toDays();
            this.fineAmount = daysLate * 2.0; // $2 per day late
        }
    }

    public boolean isOverdue() {
        return LocalDateTime.now().isAfter(dueDate) && returnDate == null;
    }

    @Override
    public String toString() {
        return String.format("Transaction[id=%s, user=%s, book=%s, borrowed=%s, due=%s%s%s]",
                           id, user.getName(), book.getName(),
                           borrowDate.toLocalDate(), dueDate.toLocalDate(),
                           returnDate != null ? ", returned=" + returnDate.toLocalDate() : "",
                           fineAmount > 0 ? ", fine=$" + fineAmount : "");
    }
}

// ==================== REPOSITORY PATTERN ====================

// Generic Repository interface
interface Repository<T extends Entity> {
    void add(T item);
    void remove(String id);
    T findById(String id);
    List<T> findAll();
    List<T> findByName(String name);
    void saveToFile(String filename) throws IOException;
    void loadFromFile(String filename) throws IOException, ClassNotFoundException;
}

// Book Repository implementation
class BookRepository implements Repository<Book> {
    private Map<String, Book> books;

    public BookRepository() {
        books = new ConcurrentHashMap<>();
        loadSampleData();
    }

    private void loadSampleData() {
        add(new Book("B001", "Effective Java", "Joshua Bloch", "9780134685991", 2018, "Programming", 5));
        add(new Book("B002", "Clean Code", "Robert C. Martin", "9780132350884", 2008, "Programming", 3));
        add(new Book("B003", "The Pragmatic Programmer", "David Thomas", "9780201616224", 2019, "Programming", 4));
        add(new Book("B004", "Design Patterns", "Erich Gamma", "9780201633610", 1994, "Programming", 2));
        add(new Book("B005", "Java: The Complete Reference", "Herbert Schildt", "9781260440232", 2018, "Programming", 6));
    }

    @Override
    public void add(Book book) {
        books.put(book.getId(), book);
    }

    @Override
    public void remove(String id) {
        books.remove(id);
    }

    @Override
    public Book findById(String id) {
        return books.get(id);
    }

    @Override
    public List<Book> findAll() {
        return new ArrayList<>(books.values());
    }

    @Override
    public List<Book> findByName(String name) {
        return books.values().stream()
            .filter(book -> book.getName().toLowerCase().contains(name.toLowerCase()))
            .collect(Collectors.toList());
    }

    public List<Book> findByAuthor(String author) {
        return books.values().stream()
            .filter(book -> book.getAuthor().toLowerCase().contains(author.toLowerCase()))
            .collect(Collectors.toList());
    }

    public List<Book> findByGenre(String genre) {
        return books.values().stream()
            .filter(book -> book.getGenre().equalsIgnoreCase(genre))
            .collect(Collectors.toList());
    }

    public List<Book> findAvailableBooks() {
        return books.values().stream()
            .filter(Book::isAvailable)
            .collect(Collectors.toList());
    }

    @Override
    public void saveToFile(String filename) throws IOException {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(new ArrayList<>(books.values()));
        }
    }

    @Override
    @SuppressWarnings("unchecked")
    public void loadFromFile(String filename) throws IOException, ClassNotFoundException {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            List<Book> loadedBooks = (List<Book>) ois.readObject();
            books.clear();
            for (Book book : loadedBooks) {
                books.put(book.getId(), book);
            }
        }
    }
}

