// Transaction Repository
class TransactionRepository {
    private List<Transaction> transactions;

    public TransactionRepository() {
        transactions = new CopyOnWriteArrayList<>();
    }

    public void add(Transaction transaction) {
        transactions.add(transaction);
    }

    public List<Transaction> findAll() {
        return new ArrayList<>(transactions);
    }

    public List<Transaction> findByUserId(String userId) {
        return transactions.stream()
            .filter(t -> t.getUser().getId().equals(userId))
            .collect(Collectors.toList());
    }

    public List<Transaction> findOverdueTransactions() {
        return transactions.stream()
            .filter(Transaction::isOverdue)
            .collect(Collectors.toList());
    }

    public void saveToFile(String filename) throws IOException {
        try (ObjectOutputStream oos = new ObjectOutputStream(new FileOutputStream(filename))) {
            oos.writeObject(new ArrayList<>(transactions));
        }
    }

    @SuppressWarnings("unchecked")
    public void loadFromFile(String filename) throws IOException, ClassNotFoundException {
        try (ObjectInputStream ois = new ObjectInputStream(new FileInputStream(filename))) {
            List<Transaction> loadedTransactions = (List<Transaction>) ois.readObject();
            transactions.clear();
            transactions.addAll(loadedTransactions);
        }
    }
}

// ==================== SERVICE LAYER ====================

// Library Service
class LibraryService {
    private BookRepository bookRepository;
    private UserRepository userRepository;
    private TransactionRepository transactionRepository;

    public LibraryService() {
        this.bookRepository = new BookRepository();
        this.userRepository = new UserRepository();
        this.transactionRepository = new TransactionRepository();
    }

    // Book operations
    public void addBook(Book book) {
        bookRepository.add(book);
    }

    public List<Book> searchBooks(String query) {
        List<Book> results = new ArrayList<>();
        results.addAll(bookRepository.findByName(query));
        results.addAll(bookRepository.findByAuthor(query));
        return results.stream().distinct().collect(Collectors.toList());
    }

    public List<Book> getAvailableBooks() {
        return bookRepository.findAvailableBooks();
    }

    // User operations
    public void addUser(User user) {
        userRepository.add(user);
    }

    // Transaction operations
    public Transaction borrowBook(String userId, String bookId) throws LibraryException {
        User user = userRepository.findById(userId);
        Book book = bookRepository.findById(bookId);

        if (user == null) {
            throw new LibraryException("User not found");
        }
        if (book == null) {
            throw new LibraryException("Book not found");
        }
        if (!book.isAvailable()) {
            throw new LibraryException("Book is not available");
        }
        if (!user.canBorrowMore()) {
            throw new LibraryException("User has reached borrow limit");
        }

        // Perform borrow operation
        book.borrowCopy();
        user.borrowBook(book);

        Transaction transaction = new Transaction(user, book);
        transactionRepository.add(transaction);

        return transaction;
    }

    public Transaction returnBook(String userId, String bookId) throws LibraryException {
        // Find active transaction
        Transaction transaction = transactionRepository.findByUserId(userId).stream()
            .filter(t -> t.getBook().getId().equals(bookId) && t.getReturnDate() == null)
            .findFirst()
            .orElseThrow(() -> new LibraryException("No active borrow record found"));

        // Perform return operation
        transaction.getBook().returnCopy();
        transaction.getUser().returnBook(transaction.getBook());
        transaction.returnBook();

        return transaction;
    }

    // Report generation
    public Map<String, Object> generateReport() {
        Map<String, Object> report = new HashMap<>();

        report.put("totalBooks", bookRepository.findAll().size());
        report.put("availableBooks", bookRepository.findAvailableBooks().size());
        report.put("totalUsers", userRepository.findAll().size());
        report.put("activeTransactions", transactionRepository.findAll().stream()
            .filter(t -> t.getReturnDate() == null).count());
        report.put("overdueTransactions", transactionRepository.findOverdueTransactions().size());

        // Popular books
        Map<Book, Long> bookBorrowCount = transactionRepository.findAll().stream()
            .collect(Collectors.groupingBy(Transaction::getBook, Collectors.counting()));
        report.put("popularBooks", bookBorrowCount.entrySet().stream()
            .sorted(Map.Entry.<Book, Long>comparingByValue().reversed())
            .limit(5)
            .collect(Collectors.toList()));

        return report;
    }

    // Data persistence
    public void saveData() throws IOException {
        bookRepository.saveToFile("books.dat");
        userRepository.saveToFile("users.dat");
        transactionRepository.saveToFile("transactions.dat");
    }

    public void loadData() throws IOException, ClassNotFoundException {
        bookRepository.loadFromFile("books.dat");
        userRepository.loadFromFile("users.dat");
        transactionRepository.loadFromFile("transactions.dat");
    }
}

