                    Map.Entry<Book, Long> entry = popularBooks.get(i);
                    System.out.printf("  %d. %s (borrowed %d times)%n", 
                                     i + 1, entry.getKey().getName(), entry.getValue());
                }
            }
        }

        @Override
        public String getDescription() {
            return "Generate Report";
        }
    }

    class AddBookCommand implements Command {
        @Override
        public void execute() {
            System.out.println("\nAdd New Book:");

            System.out.print("Book ID: ");
            String id = scanner.nextLine();

            System.out.print("Title: ");
            String title = scanner.nextLine();

            System.out.print("Author: ");
            String author = scanner.nextLine();

            System.out.print("ISBN: ");
            String isbn = scanner.nextLine();

            System.out.print("Publication Year: ");
            int year = Integer.parseInt(scanner.nextLine());

            System.out.print("Genre: ");
            String genre = scanner.nextLine();

            System.out.print("Number of Copies: ");
            int copies = Integer.parseInt(scanner.nextLine());

            Book book = new Book(id, title, author, isbn, year, genre, copies);
            libraryService.addBook(book);

            System.out.println("\nBook added successfully!");
        }

        @Override
        public String getDescription() {
            return "Add New Book";
        }
    }

    class AddUserCommand implements Command {
        @Override
        public void execute() {
            System.out.println("\nAdd New User:");

            System.out.print("User ID: ");
            String id = scanner.nextLine();

            System.out.print("Name: ");
            String name = scanner.nextLine();

            System.out.println("User Type (1-Student, 2-Faculty, 3-Staff, 4-Guest): ");
            int typeChoice = Integer.parseInt(scanner.nextLine());
            UserType type = UserType.values()[typeChoice - 1];

            System.out.print("Email: ");
