    class LoadDataCommand implements Command {
        @Override
        public void execute() {
            try {
                libraryService.loadData();
                System.out.println("Data loaded successfully!");
            } catch (Exception e) {
                System.out.println("Error loading data: " + e.getMessage());
            }
        }

        @Override
        public String getDescription() {
